Javascript.miscCode:
	
		//--------------------------------------- VisitsGrid ---------------------------------
		VisitsGrid.srcData = "/ds/EnterVariableData/ConfNotice/visits";
		VisitsGrid.rowXPath = "visit";
		VisitsGrid.keyXPath = "visitid";
		VisitsGrid.columns = [
			{xpath: "date", transformToDisplay: CaseManUtils.formatGridDate},
			{xpath: "time"},
			{xpath: "result"} ];
		
		//-------------------------------------  VisitPopupBtn  ----------------------------------------

		function VisitPopupBtn() {}
	
		VisitPopupBtn.actionBinding = function() 
		{	
			Services.dispatchEvent("Visits_Popup", PopupGUIAdaptor.EVENT_RAISE); 
			Services.setValue(VisitDate.dataBinding, "");
			Services.setValue(VisitTime.dataBinding, "");
			Services.setValue(VisitResult.dataBinding, "");
		}
		VisitPopupBtn.isEnabled = function()
		{	return true;
		}
		VisitPopupBtn.tabIndex = __tabIdx++;
	
	
		//-------------------------------------  VisitAddBtn  ------------------------------------------
	
		var VISIT_COUNT = 0;
	
		function VisitAddBtn(){}
		VisitAddBtn.actionBinding = function()
		{		
			var visitDate   = Services.getValue(VisitDate.dataBinding); //CaseManUtils.convertDateToDisplay( Services.getValue(VisitDate.dataBinding));
			var visitTime   = Services.getValue(VisitTime.dataBinding);
			var visitResult = Services.getValue(VisitResult.dataBinding);

			// Need to ensure all mandatory data is entered and all data is valid

			var screenValid = true;
			if( (visitDate == null || visitDate == "") || 
				(visitTime == null || visitTime == "") || 
				(visitResult == null || visitResult == ""))
			{
			screenValid = false;	
			}
	
			if(screenValid)
			{   VISIT_COUNT++;
				// Set the data in to the business part of the model		
				var visitDOM= XML.createDOM();
				visitDOM.loadXML("<visit>"+
								"<visitid>" + VISIT_COUNT +"</visitid>"+
								"<date>"+ visitDate + "</date>"+
								"<time>" + visitTime + "</time>"+
								"<result>" + visitResult + "</result>"+
							"</visit>");
				Services.addNode(visitDOM, "/ds/EnterVariableData/ConfNotice/visits");
			
				FormController.getInstance().hideFormExtensionPopup("Visits_Popup");
			}		
		}



		//--------------------------------------- VisitCancelBtn ---------------------------------------
		
		function VisitCancelBtn(){}
		VisitCancelBtn.actionBinding = function()
		{	
			FormController.getInstance().hideFormExtensionPopup("Visits_Popup");
		}	
		VisitCancelBtn.nextFocusedAdaptorId = function()
		{ return 'VisitPopupBtn';   //force framework to move to next available field
		}
		
	
		
		
		//--------------------------------------- VisitDate -------------------------------------
	
		function VisitDate(){}
		VisitDate.dataBinding 	= "/ds/var/app/WPData/bailiffvisit/visitdate";
		VisitDate.helpText 		= "Select the date of visit";
		VisitDate.validateOn 	= [VisitDate.dataBinding];
		VisitDate.validate 		= function(value)
		{	
			return isInPast(Services.getValue(VisitDate.dataBinding),"false");
		}
		
		
		//--------------------------------------- VisitTime -------------------------------------
		
		function VisitTime(){}
		VisitTime.dataBinding 	= "/ds/var/app/WPData/bailiffvisit/time";
		VisitTime.helpText 		= "Enter the time of visit";
		VisitTime.validateOn 	= [VisitTime.dataBinding];
		VisitTime.validate 		= function(value)
		{	
			return validateTimeAt(WPU.transformTimeToModel(Services.getValue(VisitTime.dataBinding)));				
		}
		
		//--------------------------------------- VisitResult -----------------------------------
		
		function VisitResult(){}
		VisitResult.dataBinding = "/ds/var/app/WPData/bailiffvisit/resultofvisit";	
		VisitResult.helpText = "Enter the result of visit";
		
		//--------------------------------------- Visits_Popup  ---------------------------------
		
		function Visits_Popup(){}
		Visits_Popup.nextFocusedAdaptorId = function()
		{ return 'VisitPopupBtn';   //force framework to move to next available field
		}
